#include &lt;stdio.h&gt;
#include &lt;stdlib.h&gt;

void write_and_read() {
    // 1. Open file for Writing (creates file, or wipes it if it exists)
    FILE *file = fopen("config.txt", "w");
    if (file == NULL) {
        perror("Failed to open file"); // Prints standard OS error
        return;
    }

    // Write data to the stream buffer
    fprintf(file, "ServerPort=%d\n", 8080);

    // Mandatory cleanup: Flushes the buffer to disk and releases OS locks
    fclose(file); 

    // 2. Open file for Reading
    file = fopen("config.txt", "r");
    if (!file) return;

    char buffer[256];
    // fgets safely reads a string up to a newline or limit (256)
    if (fgets(buffer, sizeof(buffer), file) != NULL) {
        printf("Read from disk: %s", buffer);
    }
    fclose(file);
}

#include &lt;stdio.h&gt;
#include &lt;stdint.h&gt;

struct PlayerState { uint32_t id; float health; };

void save_game(struct PlayerState *state) {
    // 'wb' explicitly requests Binary Mode. (Crucial on Windows to prevent 
    // the OS from secretly modifying '\n' bytes into '\r\n' bytes!).
    FILE *save_file = fopen("save.dat", "wb");
    if (!save_file) return;

    // fwrite blasts raw RAM bytes directly to the file stream.
    // Extremely fast. No ASCII text formatting overhead.
    fwrite(state, sizeof(struct PlayerState), 1, save_file);
    fclose(save_file);
}

