#include &lt;stdio.h&gt;
#include &lt;stdarg.h&gt;

// A function that sums an unknown number of integers
int sum_all(int count, ...) {
    va_list args;
    int total = 0;

    // 1. Initialize the pointer to sit immediately after 'count'
    va_start(args, count);

    // 2. We must rely on 'count' to know when to stop. The stack has no end marker.
    for (int i = 0; i < count; i++) {
        // Read the next 4 bytes as an int, advance the pointer.
        total += va_arg(args, int);
    }

    // 3. Mandatory cleanup. Releases internal compiler routing registers.
    va_end(args);

    return total;
}

int main() {
    printf("Sum: %d\n", sum_all(3, 10, 20, 30)); // Output: 60
    return 0;
}

