// We want a function that acts exactly like printf, but pre-pends "[ERROR]"
void log_error(const char *format, ...) {
    printf("[ERROR] ");

    va_list args;
    va_start(args, format);

    // We CANNOT pass '...' into another variadic function directly.
    // We must pass the resolved 'va_list' state pointer using the 'v' variant functions.
    vprintf(format, args);

    va_end(args);
    printf("\n");
}

int main() {
