#include "network.h"
#include &lt;stdlib.h&gt;
#include &lt;stdio.h&gt;

// 1. The FULL definition. Only the compiler building this specific .c file sees this.
struct NetClient {
    int socket_fd;
    char ip_address[64];
    int internal_state_flag;
};

NetClient* net_create(const char *ip) {
    // We must use the Heap. The client cannot allocate this on their Stack 
    // because their compiler doesn't know the size.
    NetClient *client = malloc(sizeof(NetClient));
    if (client) {
        client->socket_fd = -1;
        client->internal_state_flag = 0;
    }
    return client;
}

void net_connect(NetClient *client) {
    if (!client) return;
    // Because we are inside network.c, we have full access to the members
    client->socket_fd = 8080;
    printf("Connected.\n");
}

void net_destroy(NetClient *client) {
    free(client);
}

